<script setup lang="ts">
import{computed,ref,watch}from'vue'
import{RouterLink}from'vue-router'
import{ArrowLeft,ArrowRight,BookOpen,Brain,Check,CheckCircle2,ChevronRight,Headphones,Languages,MessageCircle,MessageSquare,ShieldAlert,XCircle}from'lucide-vue-next'
import LessonAudioPlayer from'@/components/lesson/LessonAudioPlayer.vue'
import ConversationPractice from'@/components/lesson/engine/ConversationPractice.vue'
import FlashcardDeck from'@/components/lesson/engine/FlashcardDeck.vue'
import ErrorClinic from'@/components/lesson/engine/ErrorClinic.vue'
import TranslationPractice from'@/components/lesson/engine/TranslationPractice.vue'
import ActivePractice from'@/components/lesson/engine/ActivePractice.vue'
import{useLearningProgress}from'@/composables/useLearningProgress'
import{useCourseStore}from'@/stores/courses'
import type{BlockType,Lesson,LessonBlock}from'@/types/course'
const props=defineProps<{lesson:Lesson}>();const store=useCourseStore(),progress=useLearningProgress(),active=ref('theory'),answers=ref<Record<string,number>>({}),completedSections=ref<string[]>([...progress.sections(props.lesson.id)])
watch(()=>props.lesson.id,()=>{active.value='theory';answers.value={};completedSections.value=[...progress.sections(props.lesson.id)]})
const definitions=[{id:'theory',label:'Теория',icon:BookOpen,types:['heading','grammar','callout','text','vocabulary']as BlockType[]},{id:'conversation',label:'Диалог',icon:MessageCircle,types:['conversation']as BlockType[]},{id:'listening',label:'Listening',icon:Headphones,types:['audio']as BlockType[]},{id:'cards',label:'Карточки',icon:Brain,types:['flashcards']as BlockType[]},{id:'errors',label:'Ошибки',icon:ShieldAlert,types:['error_correction']as BlockType[]},{id:'translation',label:'Перевод',icon:Languages,types:['translation']as BlockType[]},{id:'practice',label:'Практика',icon:Check,types:['practice']as BlockType[]},{id:'test',label:'Тест',icon:CheckCircle2,types:['single_choice']as BlockType[]}]
const sections=computed(()=>definitions.map(section=>({...section,blocks:props.lesson.blocks.filter(block=>section.types.includes(block.type))})).filter(section=>section.blocks.length));const current=computed(()=>sections.value.find(section=>section.id===active.value)??sections.value[0]);const questions=computed(()=>props.lesson.blocks.filter(block=>block.type==='single_choice'));const answered=computed(()=>questions.value.filter(block=>answers.value[block.id]!==undefined).length);const correct=computed(()=>questions.value.filter(block=>answers.value[block.id]===block.correctOption).length)
const found=computed(()=>store.findLesson(props.lesson.id));const allLessons=computed(()=>found.value?.course.modules.flatMap(module=>module.lessons)??[]);const lessonIndex=computed(()=>allLessons.value.findIndex(item=>item.id===props.lesson.id));const previous=computed(()=>allLessons.value[lessonIndex.value-1]);const next=computed(()=>allLessons.value[lessonIndex.value+1]);const canFinish=computed(()=>sections.value.every(section=>completedSections.value.includes(section.id))&&answered.value===questions.value.length)
function blocks(types:BlockType[]):LessonBlock[]{return props.lesson.blocks.filter(block=>types.includes(block.type))}function mark(section:string){if(!completedSections.value.includes(section))completedSections.value.push(section);progress.markSection(props.lesson.id,section)}function answer(block:LessonBlock,index:number){answers.value[block.id]=index;if(answered.value===questions.value.length)mark('test')}function finish(){if(!canFinish.value)return;progress.completeLesson(props.lesson.id)}
</script>
<template><div class="engine-player"><header class="engine-lesson-header"><div><p class="eyebrow">English Engine · {{lesson.duration}} минут</p><h1>{{lesson.title}}</h1><p>{{sections.length}} режимов · {{questions.length}} вопросов</p></div><span v-if="progress.isCompleted(lesson.id)" class="engine-complete"><CheckCircle2/>Урок завершён</span></header><nav class="engine-section-nav" aria-label="Разделы урока"><button v-for="section in sections" :key="section.id" :class="{active:active===section.id,done:completedSections.includes(section.id)}" @click="active=section.id"><component :is="section.icon"/><span>{{section.label}}</span><Check v-if="completedSections.includes(section.id)" class="section-check"/></button></nav><main v-if="current" class="engine-lesson-body"><div class="engine-section-title"><component :is="current.icon"/><div><small>Раздел урока</small><h2>{{current.label}}</h2></div><span>{{current.blocks.length}} блоков</span></div><template v-if="current.id==='theory'"><article v-for="block in blocks(current.types)" :key="block.id" :class="['engine-theory-block',block.type]"><h2 v-if="block.type==='heading'">{{block.content}}</h2><section v-else-if="block.type==='grammar'"><small>30-минутный урок</small><h3>{{block.title}}</h3><p>{{block.content}}</p></section><aside v-else-if="block.type==='callout'"><MessageSquare/><div><b>{{block.title}}</b><p>{{block.content}}</p></div></aside><section v-else><h3>{{block.title}}</h3><p>{{block.content}}</p></section></article><button class="engine-section-complete" @click="mark('theory')"><Check/>{{completedSections.includes('theory')?'Теория изучена':'Я изучил теорию'}}</button></template><ConversationPractice v-else-if="current.id==='conversation'" v-bind="{role:current.blocks[0]?.role,prompt:current.blocks[0]?.prompt,starter:current.blocks[0]?.starter,sample:current.blocks[0]?.sampleAnswer}" @complete="mark('conversation')"/><template v-else-if="current.id==='listening'"><LessonAudioPlayer v-for="block in current.blocks" :key="block.id" :src="block.audioUrl" :title="block.title" :transcript="block.transcript" @completed="mark('listening')"/></template><FlashcardDeck v-else-if="current.id==='cards'" :cards="current.blocks[0]?.cards??[]" @complete="mark('cards')"/><ErrorClinic v-else-if="current.id==='errors'" :items="current.blocks[0]?.corrections??[]" @complete="mark('errors')"/><TranslationPractice v-else-if="current.id==='translation'" :source="current.blocks[0]?.sourceText" :target="current.blocks[0]?.targetText" :questions="current.blocks[0]?.comprehensionQuestions" @complete="mark('translation')"/><template v-else-if="current.id==='practice'"><ActivePractice v-for="block in current.blocks" :key="block.id" :title="block.title" :content="block.content" @complete="mark('practice')"/></template><template v-else><section v-for="(block,index) in current.blocks" :key="block.id" class="engine-test-question"><small>{{block.title}}</small><h3>{{index+1}}. {{block.content}}</h3><button v-for="(option,optionIndex) in block.options" :key="option" :class="{selected:answers[block.id]===optionIndex,correct:answers[block.id]!==undefined&&optionIndex===block.correctOption,wrong:answers[block.id]===optionIndex&&optionIndex!==block.correctOption}" @click="answer(block,optionIndex)">{{option}}<CheckCircle2 v-if="answers[block.id]!==undefined&&optionIndex===block.correctOption"/><XCircle v-else-if="answers[block.id]===optionIndex"/></button><div v-if="answers[block.id]!==undefined" class="engine-test-explanation"><b>{{answers[block.id]===block.correctOption?'Верно':'Ошибка разобрана'}}</b><p>{{block.explanation}}</p><button v-if="answers[block.id]!==block.correctOption" @click="active='theory'"><BookOpen/>Быстро перейти к теории</button></div></section><div v-if="answered" class="engine-test-result"><span>Результат</span><strong>{{correct}} из {{questions.length}}</strong><p>{{answered<questions.length?`Осталось ответить: ${questions.length-answered}`:correct===questions.length?'Все ответы верны':'Вернитесь к ошибкам и исправьте ответы'}}</p></div></template></main><footer class="engine-lesson-footer"><RouterLink v-if="previous" :to="`/preview/lessons/${previous.id}`"><ArrowLeft/>{{previous.title}}</RouterLink><span v-else></span><button :disabled="!canFinish" @click="finish"><CheckCircle2/>Завершить день</button><RouterLink v-if="next" :to="`/preview/lessons/${next.id}`">Следующий день<ArrowRight/></RouterLink><span v-else></span></footer></div></template>